# Simulate the burden of proof argument: if no evidence is provided, default to absence of belief
def burden_of_proof(theist_claims_evidence: bool) -> str:
    if theist_claims_evidence:
        return "Theist must justify claims with evidence."
    else:
        return "Atheist stance (no belief) is justified due to lack of evidence."

# Example usage
print(burden_of_proof(False))  # Output: "Atheist stance (no belief) is justified due to lack of evidence."
